/**
 * AutomationEnginePropertyPanel
 * Author: generated by Amazon Q
 * Created: 2025-01-01
 * Purpose: Full visual editor for AutomationEngineSection fields
 */

'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';

interface Props {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';
const textareaCls = inputCls + ' resize-none';

function Collapsible({ title, badge, children, defaultOpen = false }: {
  title: string; badge?: string; children: React.ReactNode; defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button type="button" onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left">
        <span className="text-sm font-medium text-gray-800 dark:text-white flex items-center gap-2">
          {title}
          {badge && <span className="text-xs bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded-full">{badge}</span>}
        </span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

export function AutomationEnginePropertyPanel({ section, onUpdate }: Props) {
  const data = section.data as any;
  const update = (patch: Record<string, any>) => onUpdate({ data: { ...data, ...patch } });

  const stats = data.stats ?? [];
  const triggers = data.triggers ?? [];
  const flowNodes = data.flowNodes ?? [];

  const updateStat = (idx: number, field: string, val: string) => {
    const next = stats.map((s: any, i: number) => i === idx ? { ...s, [field]: val } : s);
    update({ stats: next });
  };

  const updateTrigger = (idx: number, val: string) => {
    const next = triggers.map((t: any, i: number) => i === idx ? { ...t, text: val } : t);
    update({ triggers: next });
  };

  const updateNode = (idx: number, field: string, val: any) => {
    const next = flowNodes.map((n: any, i: number) => i === idx ? { ...n, [field]: val } : n);
    update({ flowNodes: next });
  };

  return (
    <div className="space-y-4">

      <Collapsible title="Text Content" defaultOpen>
        <Field label="Tag (eyebrow)">
          <input className={inputCls} value={data.tag ?? ''} onChange={e => update({ tag: e.target.value })} />
        </Field>
        <Field label="Title">
          <input className={inputCls} value={data.title ?? ''} onChange={e => update({ title: e.target.value })} />
        </Field>
        <Field label="Title Highlight (gradient)">
          <input className={inputCls} value={data.titleHighlight ?? ''} onChange={e => update({ titleHighlight: e.target.value })} />
        </Field>
        <Field label="Body">
          <textarea className={textareaCls} rows={4} value={data.body ?? ''} onChange={e => update({ body: e.target.value })} />
        </Field>
      </Collapsible>

      <Collapsible title="Stats" badge={`${stats.length}`}>
        {stats.map((s: any, i: number) => (
          <div key={i} className="flex gap-2 items-start">
            <div className="flex-1 space-y-1">
              <input className={inputCls} placeholder="Value (e.g. 5–8×)" value={s.value ?? ''} onChange={e => updateStat(i, 'value', e.target.value)} />
              <input className={inputCls} placeholder="Label" value={s.label ?? ''} onChange={e => updateStat(i, 'label', e.target.value)} />
            </div>
            <button type="button" onClick={() => update({ stats: stats.filter((_: any, si: number) => si !== i) })}
              className="mt-1 p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded">✕</button>
          </div>
        ))}
        <button type="button" onClick={() => update({ stats: [...stats, { value: '', label: '' }] })}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
          + Add Stat
        </button>
      </Collapsible>

      <Collapsible title="Trigger Chips" badge={`${triggers.length}`}>
        {triggers.map((t: any, i: number) => (
          <div key={i} className="flex gap-2">
            <input className={`flex-1 ${inputCls}`} value={t.text ?? ''} onChange={e => updateTrigger(i, e.target.value)} placeholder="Trigger name" />
            <button type="button" onClick={() => update({ triggers: triggers.filter((_: any, ti: number) => ti !== i) })}
              className="p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded">✕</button>
          </div>
        ))}
        <button type="button" onClick={() => update({ triggers: [...triggers, { text: 'New trigger' }] })}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
          + Add Trigger
        </button>
      </Collapsible>

      <Collapsible title="Flow Nodes (Visual)" badge={`${flowNodes.length}`}>
        {flowNodes.map((node: any, i: number) => (
          <div key={i} className="p-2 border border-gray-200 dark:border-gray-600 rounded-lg space-y-2">
            <div className="flex justify-between items-center">
              <span className="text-xs text-gray-500">Node {i + 1}</span>
              <button type="button" onClick={() => update({ flowNodes: flowNodes.filter((_: any, ni: number) => ni !== i) })}
                className="text-xs text-red-500 hover:text-red-700">✕ Remove</button>
            </div>
            <Field label="Label">
              <input className={inputCls} value={node.label ?? ''} onChange={e => updateNode(i, 'label', e.target.value)} />
            </Field>
            <div className="grid grid-cols-2 gap-2">
              <Field label="Variant">
                <select className={inputCls} value={node.variant ?? 'default'} onChange={e => updateNode(i, 'variant', e.target.value)}>
                  <option value="accent">Accent (blue)</option>
                  <option value="purple">Purple</option>
                  <option value="green">Green</option>
                  <option value="default">Default (gray)</option>
                </select>
              </Field>
              <Field label="Indent (0–3)">
                <select className={inputCls} value={node.indent ?? 0} onChange={e => updateNode(i, 'indent', Number(e.target.value))}>
                  {[0, 1, 2, 3].map(n => <option key={n} value={n}>{n}</option>)}
                </select>
              </Field>
            </div>
          </div>
        ))}
        <button type="button"
          onClick={() => update({ flowNodes: [...flowNodes, { label: 'New node', variant: 'default', indent: 0 }] })}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
          + Add Node
        </button>
      </Collapsible>

      <Collapsible title="Accent Colors">
        <div className="grid grid-cols-3 gap-2">
          {(['accentColor', 'accentColor2', 'accentColor3'] as const).map((key, i) => (
            <Field key={key} label={['Blue', 'Purple', 'Green'][i]}>
              <div className="flex gap-1 items-center">
                <input type="color" value={data[key] ?? '#4F7FFF'} onChange={e => update({ [key]: e.target.value })}
                  className="w-9 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700" />
                <input className={inputCls} value={data[key] ?? ''} onChange={e => update({ [key]: e.target.value })} />
              </div>
            </Field>
          ))}
        </div>
      </Collapsible>

    </div>
  );
}
